import java.util.*;
public class SubarraySumDivisible {
    public static boolean checkSubarraySum(int[] nums, int k) {
        // remainder → index where this remainder was first seen
        Map<Integer,Integer> firstSeen = new HashMap<>();
        firstSeen.put(0, -1); // remainder 0 seen before index 0
        int sum = 0;
        for (int i = 0; i < nums.length; i++) {
            sum += nums[i];
            int rem = sum % k;
            if (firstSeen.containsKey(rem)) {
                if (i - firstSeen.get(rem) >= 2) return true; // length >= 2
            } else {
                firstSeen.put(rem, i);
            }
        }
        return false;
    }
    public static void main(String[] args) {
        System.out.println(checkSubarraySum(new int[]{23,2,4,6,7}, 6)); // true
        System.out.println(checkSubarraySum(new int[]{23,2,6,4,7}, 6)); // true
        System.out.println(checkSubarraySum(new int[]{23,2,6,4,7}, 13)); // false
    }
}

