public class MatrixRangeSum {
    int[][] prefix;
    public MatrixRangeSum(int[][] matrix) {
        int m = matrix.length, n = matrix[0].length;
        prefix = new int[m+1][n+1];
        for (int i=1;i<=m;i++)
            for (int j=1;j<=n;j++)
                prefix[i][j] = matrix[i-1][j-1]
                    + prefix[i-1][j] + prefix[i][j-1] - prefix[i-1][j-1];
    }
    public int sumRegion(int r1, int c1, int r2, int c2) {
        return prefix[r2+1][c2+1] - prefix[r1][c2+1]
             - prefix[r2+1][c1] + prefix[r1][c1];
    }
    public static void main(String[] args) {
        int[][] m = {{3,0,1,4,2},{5,6,3,2,1},{1,2,0,1,5},{4,1,0,1,7},{1,0,3,0,5}};
        MatrixRangeSum obj = new MatrixRangeSum(m);
        System.out.println(obj.sumRegion(2,1,4,3)); // 8
        System.out.println(obj.sumRegion(1,1,2,2)); // 11
        System.out.println("2D prefix: O(mn) build, O(1) query");
    }
}

