exercises.expected_solution:
public class MaxSubarray {
    // Kadane's: O(n) time, O(1) space
    static int kadane(int[] nums) {
        int curr = nums[0], max = nums[0];
        for (int i = 1; i < nums.length; i++) {
            curr = Math.max(nums[i], curr + nums[i]);
            max = Math.max(max, curr);
        }
        return max;
    }
    // Prefix approach: max(prefix[j] - min_prefix_before_j)
    static int prefixApproach(int[] nums) {
        int sum = 0, minPrefix = 0, maxSum = Integer.MIN_VALUE;
        for (int num : nums) {
            sum += num;
            maxSum = Math.max(maxSum, sum - minPrefix);
            minPrefix = Math.min(minPrefix, sum);
        }
        return maxSum;
    }
    public static void main(String[] args) {
        int[] nums = {-2,1,-3,4,-1,2,1,-5,4};
        System.out.println(kadane(nums));        // 6
        System.out.println(prefixApproach(nums)); // 6
        System.out.println("Both agree: " + (kadane(nums)==prefixApproach(nums)));
        System.out.println("Kadane: O(n) O(1) — cleaner. Prefix: O(n) O(1) — intuitive.");
    }
}

