import java.util.*;
public class LongestWellPerforming {
    public static int longestWPI(int[] hours) {
        // Convert: tiring(>8)=+1, non-tiring=-1
        // Find longest subarray with positive sum
        Map<Integer,Integer> firstSeen = new HashMap<>();
        int sum = 0, maxLen = 0;
        for (int i = 0; i < hours.length; i++) {
            sum += hours[i] > 8 ? 1 : -1;
            if (sum > 0) {
                maxLen = i + 1; // entire prefix is well-performing
            } else {
                // Find earliest index where prefix was sum-1
                // (if prefix[j]=sum, prefix[i]=sum-1 → subarray[i+1..j] sums to 1 > 0)
                if (firstSeen.containsKey(sum - 1)) {
                    maxLen = Math.max(maxLen, i - firstSeen.get(sum - 1));
                }
            }
            firstSeen.putIfAbsent(sum, i); // only store first occurrence
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(longestWPI(new int[]{9,9,6,0,6,6,9})); // 3
        System.out.println(longestWPI(new int[]{6,6,6}));          // 0
        System.out.println("O(n) — prefix sum + HashMap first-seen index");
    }
}

