import java.util.*;
public class MinOpsBalance {
    static int minLengthSubarrayDivisibleByN(int[] nums) {
        int n = nums.length;
        // Find smallest subarray sum divisible by n
        Map<Integer,Integer> firstSeen = new HashMap<>();
        firstSeen.put(0, -1); // prefix sum 0 seen before index 0
        int sum = 0, minLen = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            sum = ((sum + nums[i]) % n + n) % n; // handle negative mods
            if (firstSeen.containsKey(sum)) {
                int len = i - firstSeen.get(sum);
                if (len > 0) minLen = Math.min(minLen, len);
            } else {
                firstSeen.put(sum, i);
            }
        }
        return minLen == Integer.MAX_VALUE ? -1 : minLen;
    }
    public static void main(String[] args) {
        System.out.println(minLengthSubarrayDivisibleByN(new int[]{2,3,1,4})); // 2
        System.out.println(minLengthSubarrayDivisibleByN(new int[]{1,2,3}));   // 3
        System.out.println("O(n) — prefix sum mod n + HashMap");
    }
}

