import java.util.Arrays;
public class KRadiusAverage {
    public static int[] getAverages(int[] nums, int k) {
        int n = nums.length;
        int[] result = new int[n];
        Arrays.fill(result, -1);
        // Prefix sums:
        long[] prefix = new long[n+1];
        for (int i=0;i<n;i++) prefix[i+1]=prefix[i]+nums[i];
        // Fill valid positions:
        for (int i=k; i<n-k; i++) {
            long windowSum = prefix[i+k+1] - prefix[i-k];
            result[i] = (int)(windowSum / (2*k+1));
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(getAverages(new int[]{7,4,3,9,1,8,5,2,6}, 3)));
        System.out.println(Arrays.toString(getAverages(new int[]{100000}, 0)));
        System.out.println("O(n) — prefix sum for O(1) window sum at each index");
    }
}

