import java.util.*;
public class PrefixSynthesis {
    static int[] buildPrefix(int[] nums){
        int[] p=new int[nums.length+1];
        for(int i=0;i<nums.length;i++) p[i+1]=p[i]+nums[i];
        return p;
    }
    static int rangeSum(int[] prefix, int l, int r){ return prefix[r+1]-prefix[l]; }
    static int subarraySumK(int[] nums, int k){
        Map<Integer,Integer> cnt=new HashMap<>(); cnt.put(0,1);
        int sum=0,count=0;
        for(int n:nums){sum+=n;count+=cnt.getOrDefault(sum-k,0);cnt.merge(sum,1,Integer::sum);}
        return count;
    }
    static int[] productExceptSelf(int[] nums){
        int n=nums.length; int[] res=new int[n]; res[0]=1;
        for(int i=1;i<n;i++) res[i]=res[i-1]*nums[i-1];
        int right=1;
        for(int i=n-1;i>=0;i--){res[i]*=right;right*=nums[i];}
        return res;
    }
    public static void main(String[] args){
        int[] nums={1,2,3,4,5};
        int[] p=buildPrefix(nums);
        System.out.println("rangeSum(1,3)="+rangeSum(p,1,3)); // 2+3+4=9
        System.out.println("subarraySumK([1,1,1],2)="+subarraySumK(new int[]{1,1,1},2)); // 2
        System.out.println("productExceptSelf([1,2,3,4])="+Arrays.toString(productExceptSelf(new int[]{1,2,3,4}))); // [24,12,8,6]
        boolean allPass = rangeSum(p,1,3)==9
            && subarraySumK(new int[]{1,1,1},2)==2
            && Arrays.equals(productExceptSelf(new int[]{1,2,3,4}),new int[]{24,12,8,6});
        System.out.println("All pass: "+allPass);
    }
}
